import * as AasXmlization from "../src/xmlization";
import * as AasTypes from "../src/types";

import * as TestCommonXmlization from "./commonXmlization";

test(
  "IAbstractItem XML round-trip " +
  "starting from AnotherItem OK",
  () => {
    const instance = TestCommonXmlization.loadMinimalAnotherItem();

    const xmlText = AasXmlization.toXmlString(instance);
    const anotherInstanceOrError = AasXmlization.fromXmlString(xmlText);
    expect(anotherInstanceOrError.error).toBeNull();
    const anotherInstance = anotherInstanceOrError.mustValue();

    const asInterface = AasTypes.asAbstractItem(anotherInstance);
    expect(asInterface).not.toBeNull();
  }
);

test(
  "IAbstractItem XML round-trip " +
  "starting from SomeItem OK",
  () => {
    const instance = TestCommonXmlization.loadMinimalSomeItem();

    const xmlText = AasXmlization.toXmlString(instance);
    const anotherInstanceOrError = AasXmlization.fromXmlString(xmlText);
    expect(anotherInstanceOrError.error).toBeNull();
    const anotherInstance = anotherInstanceOrError.mustValue();

    const asInterface = AasTypes.asAbstractItem(anotherInstance);
    expect(asInterface).not.toBeNull();
  }
);

test("IAbstractItem XML deserialization fail", () => {
  const instanceOrError = AasXmlization.fromXmlString("This is not XML.");
  expect(instanceOrError.error).not.toBeNull();
});

